import React from "react";
import ReactDOM from "react-dom/client";
import App from "./App";
import { KycProvider } from "./context/KycContext";
import "./index.css";

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <React.StrictMode>
    <KycProvider>
      <App />
    </KycProvider>
  </React.StrictMode>
);
